// 필수값 검사 — P0: prompt_p1 필수, topic/keywords/category 선택(저장 전용)
try {
const body = $input.first().json.body || $input.first().json;

// payload 디버그 로깅
console.log('[AO Producer] payload keys:', JSON.stringify(Object.keys(body)));
console.log('[AO Producer] duration fields:', JSON.stringify({ duration: body.duration, duration_sec: body.duration_sec, durationSec: body.durationSec }));
console.log('[AO Producer] mode fields:', JSON.stringify({ production_mode: body.production_mode, productionMode: body.productionMode }));

// prompt_p1 필수
if (!body.prompt_p1 || !body.prompt_p1.trim()) {
  throw new Error('필수값 누락: prompt_p1');
}

// duration 범위 검증 (0=자동, 3~180초)
const rawDuration = (body.duration || body.duration_sec) ? parseInt(body.duration || body.duration_sec) : null;
if (rawDuration !== null && rawDuration !== 0 && (rawDuration < 3 || rawDuration > 180)) {
  throw new Error('duration 오류: ' + rawDuration + ' (허용: 0 또는 3~180)');
}
const duration = rawDuration;

// files 검증 (최대 10개)
const files = body.files || [];
if (files.length > 10) throw new Error(`files 최대 10개 (현재: ${files.length})`);

// generated_images 검증
const generatedImages = body.generated_images || [];

// production_mode: ai_video (기본) / slideshow
const productionMode = body.production_mode || body.productionMode || 'ai_video';
if (!['ai_video', 'slideshow'].includes(productionMode)) {
  throw new Error(`production_mode 오류: ${productionMode} (ai_video/slideshow 중 하나)`);
}

// slideshow 모드: 이미지 최소 1개 필요
if (productionMode === 'slideshow' && files.length === 0 && generatedImages.length === 0) {
  throw new Error('slideshow 모드는 이미지가 최소 1장 필요합니다.');
}

// ai_video 모드: 프롬프트 or 이미지 중 최소 1개
if (productionMode === 'ai_video' && files.length === 0 && generatedImages.length === 0 && !body.prompt_p1) {
  throw new Error('파일, 생성 이미지, 프롬프트 중 최소 1개는 필요합니다.');
}

const hasImages = files.length > 0 || generatedImages.length > 0;

// clip_duration: ai_video=3~15초(Kling), slideshow=무관
const rawDur = parseInt(body.clip_duration) || 8;
const clipDuration = productionMode === 'ai_video' ? Math.max(3, Math.min(15, rawDur)) : rawDur;
// clip_duration_mode: duration>15이고 clip_duration 미지정이면 auto
const clipDurationMode = (duration && duration > 15 && !body.clip_duration) ? 'auto' : 'fixed';

// scenes[] 검증 (멀티클립 씬별 프롬프트)
const scenes = body.scenes || [];
let scenesWarning = '';
if (scenes.length > 0) {
  for (let i = 0; i < scenes.length; i++) {
    const sd = parseInt(scenes[i].duration_sec);
    if (!sd || sd < 1 || sd > 12) throw new Error('scenes[' + i + '].duration_sec 오류: ' + scenes[i].duration_sec + ' (1~12 허용)');
    if (!scenes[i].prompt || !scenes[i].prompt.trim()) throw new Error('scenes[' + i + '].prompt 필수');
  }
  const scenesTotal = scenes.reduce((s, sc) => s + parseInt(sc.duration_sec), 0);
  if (duration && Math.abs(scenesTotal - duration) > 3) {
    throw new Error('scenes 총합(' + scenesTotal + 's)과 duration(' + duration + 's) 불일치 (허용 +-3초)');
  }
  const uniquePrompts = new Set(scenes.map(s => s.prompt.trim()));
  if (uniquePrompts.size === 1 && scenes.length > 1) {
    scenesWarning = 'all_same_prompt';
  }
}

const slideDuration = parseInt(body.slide_duration) || 3;

// aspect_ratio
const aspectRatio = body.aspect_ratio || '9:16';
if (!['9:16', '16:9'].includes(aspectRatio)) {
  throw new Error(`aspect_ratio 오류: ${aspectRatio} (9:16/16:9 중 하나)`);
}

const useMedia = body.use_media || 'forced';
const uploadTarget = body.upload_target || 'youtube';

// BGM/SFX 옵션 (bgm_mode/sfx_mode + 하위호환)
const ALLOWED_BGM = ['none', 'ai_auto', 'uploaded'];
const ALLOWED_SFX = ['none', 'ai_auto', 'uploaded', 'combined'];
let bgmMode = body.bgm_mode || (body.enable_bgm === true ? 'ai_auto' : 'none');
if (!ALLOWED_BGM.includes(bgmMode)) throw new Error('bgm_mode 오류: ' + bgmMode + ' (허용: ' + ALLOWED_BGM.join('/') + ')');
let sfxMode = body.sfx_mode || (body.enable_sfx === true ? 'ai_auto' : 'none');
if (!ALLOWED_SFX.includes(sfxMode)) throw new Error('sfx_mode 오류: ' + sfxMode + ' (허용: ' + ALLOWED_SFX.join('/') + ')');
const enableBgm = bgmMode !== 'none';
const enableSfx = sfxMode !== 'none';
const bgmUrl = body.bgm_url || '';
const sfxFileUrl = body.sfx_file_url || '';

// strict_mode / verify_mode
const strictMode = body.strict_mode === true;
const verifyMode = body.verify_mode === true;

// engine_type 검증
const ALLOWED_ENGINES = ['character_story', 'core_message', 'live_promo', 'meme', 'action_sports'];
const engineType = body.engine_type || 'core_message';
if (!ALLOWED_ENGINES.includes(engineType)) {
  throw new Error(`engine_type 오류: ${engineType} (허용값: ${ALLOWED_ENGINES.join('/')})`);
}

// narration_style 검증
const ALLOWED_STYLES = ['설명형', '스토리형', '광고형', '감성형'];
const narrationStyle = body.narration_style || '설명형';
if (!ALLOWED_STYLES.includes(narrationStyle)) {
  throw new Error(`narration_style 오류: ${narrationStyle} (허용값: ${ALLOWED_STYLES.join('/')})`);
}

// narration_tone 검증
const ALLOWED_TONES = ['차분하게', '흥분되게', '유머러스하게', '긴박하게'];
const narrationTone = body.narration_tone || '차분하게';
if (!ALLOWED_TONES.includes(narrationTone)) {
  throw new Error(`narration_tone 오류: ${narrationTone} (허용값: ${ALLOWED_TONES.join('/')})`);
}

// voice_provider 검증 (tts | kling, 기본 tts)
const ALLOWED_VOICE = ['tts', 'kling'];
const voiceProvider = body.voice_provider || 'tts';
if (!ALLOWED_VOICE.includes(voiceProvider)) {
  throw new Error('voice_provider 오류: ' + voiceProvider + ' (허용: tts/kling)');
}

// kling_group_shots 수신 (2단계 사전 분해 데이터)
const klingGroupShots = body.kling_group_shots || null;
if (klingGroupShots) {
  if (!Array.isArray(klingGroupShots)) throw new Error('kling_group_shots는 배열이어야 합니다');
  if (klingGroupShots.length > 12) throw new Error('kling_group_shots 그룹 최대 12개');
  for (let gi = 0; gi < klingGroupShots.length; gi++) {
    const g = klingGroupShots[gi];
    if (!g || !Array.isArray(g.shots)) throw new Error('kling_group_shots[' + gi + '].shots 필수');
    if (g.shots.length < 1 || g.shots.length > 5) throw new Error('kling_group_shots[' + gi + '] 샷 1~5개');
    for (let si = 0; si < g.shots.length; si++) {
      const s = g.shots[si];
      if (!s.prompt) throw new Error('kling_group_shots[' + gi + '].shots[' + si + '].prompt 필수');
      const d = parseInt(s.duration);
      if (!d || d < 1 || d > 12) throw new Error('kling_group_shots[' + gi + '].shots[' + si + '].duration 오류 (1~12)');
    }
  }
}

// narration_start_sec (선택: null=자동, 0이상=해당 초 시작)
const narrationStartSec = (body.narration_start_sec !== undefined && body.narration_start_sec !== null && body.narration_start_sec !== '')
  ? Math.max(0, parseInt(body.narration_start_sec) || 0)
  : null;

// files 정규화
const finalFiles = files.map(f => ({
  type: f.type || 'image',
  url: f.url || '',
  vision_analysis: f.vision_analysis || '',
  video_analysis: f.video_analysis || '',
  use_mode: f.use_mode || 'direct',
  auto_prompt: f.auto_prompt || '',
  skip_kling: f.skip_kling === true
}));

// 언어 감지
const isKorean = /[\uAC00-\uD7A3]/.test((body.prompt_p1 || '') + (body.topic || ''));
const translateMode = body.translate_mode || 'auto';
const needsTranslation = translateMode === 'on' || (translateMode === 'auto' && isKorean);

// Prompt Lock: SHA-256 해시 생성
const promptText = body.prompt_p1.trim();
let promptHash = '';
const hashChars = [];
for (let i = 0; i < promptText.length; i++) {
  hashChars.push(promptText.charCodeAt(i).toString(16));
}
// 간이 해시 (n8n Code 노드에서 crypto 사용 불가하므로 FNV-1a 방식)
let h = 0x811c9dc5;
for (let i = 0; i < promptText.length; i++) {
  h ^= promptText.charCodeAt(i);
  h = Math.imul(h, 0x01000193);
}
promptHash = (h >>> 0).toString(16).padStart(8, '0');
// 추가 엔트로피: 길이 + 처음/끝 4자
promptHash += '-' + promptText.length + '-' + promptText.substring(0, 4).split('').map(c => c.charCodeAt(0).toString(16)).join('');

// SQL 싱글쿼트 이스케이프
const esc = (s) => typeof s === 'string' ? s.replace(/'/g, "''") : s;

return [{
  json: {
    error: false,
    ...body,
    prompt_p1: esc(body.prompt_p1 || ''),
    topic: esc(body.topic || ''),
    keywords: esc(body.keywords || ''),
    category: esc(body.category || ''),
    narration_script: esc(body.narration_script || ''),
    narration_text: esc(body.narration_text || ''),
    production_id: body.productionId || body.production_id || null,
    production_mode: productionMode,
    has_images: hasImages,
    clips: esc(JSON.stringify(finalFiles)),
    generated_images: esc(JSON.stringify(generatedImages)),
    aspect_ratio: aspectRatio,
    clip_duration: clipDuration,
    clip_duration_mode: clipDurationMode,
    slide_duration: slideDuration,
    use_media: useMedia,
    upload_target: uploadTarget,
    prompt_lang_detected: isKorean ? 'ko' : 'en',
    needs_translation: needsTranslation,
    enable_bgm: enableBgm,
    enable_sfx: enableSfx,
    bgm_mode: bgmMode,
    sfx_mode: sfxMode,
    bgm_url: esc(bgmUrl),
    sfx_file_url: esc(sfxFileUrl),
    duration: duration,
    strict_mode: strictMode,
    verify_mode: verifyMode,
    engine_type: engineType,
    narration_style: narrationStyle,
    narration_tone: narrationTone,
    prompt_hash: promptHash,
    scenes: scenes,
    narration_start_sec: narrationStartSec,
    scenes_warning: scenesWarning,
    voice_provider: voiceProvider,
    kling_group_shots: klingGroupShots,
    validated_at: new Date().toISOString()
  }
}];
} catch (e) {
  return [{ json: { error: true, message: e.message } }];
}

const job = $input.first().json;

return [{
  json: {
    success: true,
    job_id: job.id,
    production_id: job.production_id || null,
    status: job.status,
    message: 'Job이 큐에 등록되었습니다.',
    created_at: job.created_at
  }
}];
